const install=async url=>{const path=url.substr(0,url.lastIndexOf("/")),blamElems=[...document.querySelectorAll(":not(:defined)")].filter(elem=>elem.nodeName.includes("-BLAM")),imports=[...new Set(blamElems.map(elem=>elem.nodeName.toLowerCase()))].map(name=>{let stem=name.split("-")[0],filename=stem.charAt(0).toUpperCase()+stem.slice(1);return import(`${path}/elements/${filename}.js`)});(await Promise.all(imports)).forEach(def=>{let key=Object.keys(def)[0];customElements.define(`${key.toLowerCase()}-blam`,def[key])});let ready=new CustomEvent("blamready");window.dispatchEvent(ready)};export{install};